#include <stdio.h>
bool isPalindrome(int x) {
    if (x < 0) return false;
    int rev = 0;
    int orig = x;
    while (x != 0) {
        rev = rev * 10 + x % 10;
        x /= 10;
    }
    return rev == orig;
}
int main() {
    int num = 12321;
    printf("%d is %s palindrome.\n", num, isPalindrome(num) ? "" : "not ");
    return 0;
}

